'use client'

import {
  Bell,
  Calendar,
  CheckCircle2,
  ChevronRight,
  Circle,
  Flame,
  Phone,
  Users2,
} from 'lucide-react'
import { atividadesHoje, funil, tempConfig } from '@/lib/app-data'

const metricas = [
  { label: 'Negócios abertos', valor: '7', delta: '+2 esta semana' },
  { label: 'Visitas hoje', valor: '1', delta: '15h confirmada' },
  { label: 'Leads quentes', valor: '4', delta: 'ação imediata' },
]

export function ScreenHoje({
  onVerFunil,
  onVerCliente,
}: {
  onVerFunil: () => void
  onVerCliente: (id: string) => void
}) {
  const leadsQuentes = funil
    .flatMap((estagio) => estagio.leads.map((lead) => ({ ...lead, estagio: estagio.nome })))
    .filter((lead) => lead.temperatura === 'quente')
    .slice(0, 3)

  const pendentes = atividadesHoje.filter((a) => !a.concluida)

  return (
    <div className="flex flex-col gap-6 px-5 pt-4 pb-28">
      <header className="flex items-start justify-between">
        <div>
          <p className="font-mono text-[11px] uppercase tracking-[0.18em] text-muted-foreground">
            Segunda, 6 de julho
          </p>
          <h1 className="mt-1 font-serif text-2xl font-semibold text-foreground text-balance">
            Bom dia, Corretor
          </h1>
        </div>
        <button
          type="button"
          aria-label="Notificações"
          className="relative flex size-10 items-center justify-center rounded-full bg-card border border-border text-foreground shadow-sm transition-brand active:scale-95"
        >
          <Bell className="size-5" strokeWidth={1.5} />
          <span className="absolute right-2 top-2 size-2 rounded-full bg-amber" aria-hidden="true" />
        </button>
      </header>

      {/* Calendário horizontal mini */}
      <section aria-label="Calendário da semana">
        <div className="flex justify-between px-1">
          {['Dom 5', 'Seg 6', 'Ter 7', 'Qua 8', 'Qui 9', 'Sex 10', 'Sáb 11'].map((dia, idx) => {
            const [semana, numero] = dia.split(' ')
            const isHoje = idx === 1 // "Seg 6" is active based on hardcoded date
            return (
              <button
                key={dia}
                type="button"
                className={`flex flex-col items-center gap-1 rounded-[1.25rem] p-2 transition-brand min-w-[3rem] ${
                  isHoje
                    ? 'bg-primary text-primary-foreground shadow-lg shadow-primary/30'
                    : 'text-muted-foreground active:bg-muted/50'
                }`}
              >
                <span className="text-[10px] uppercase font-semibold">{semana}</span>
                <span
                  className={`text-lg font-serif ${
                    isHoje ? 'font-semibold' : 'font-medium text-foreground'
                  }`}
                >
                  {numero}
                </span>
              </button>
            )
          })}
        </div>
      </section>

      {/* Métricas em carrossel horizontal */}
      <section aria-label="Indicadores do dia">
        <div className="flex gap-3 overflow-x-auto scrollbar-none -mx-5 px-5 snap-x snap-mandatory">
          {metricas.map((m, i) => (
            <div
              key={m.label}
              className={`min-w-[140px] snap-start rounded-3xl p-4 transition-brand ${
                i === 0
                  ? 'bg-primary text-primary-foreground shadow-lg shadow-primary/20'
                  : 'bg-card text-foreground shadow-soft'
              }`}
            >
              <p
                className={`font-mono text-3xl font-medium ${
                  i === 0 ? 'text-primary-foreground' : 'text-primary'
                }`}
              >
                {m.valor}
              </p>
              <p className={`mt-1 text-xs font-medium ${i === 0 ? 'text-primary-foreground/90' : 'text-foreground'}`}>
                {m.label}
              </p>
              <p className={`mt-0.5 text-[11px] ${i === 0 ? 'text-teal-light' : 'text-muted-foreground'}`}>
                {m.delta}
              </p>
            </div>
          ))}
        </div>
      </section>

      {/* Agenda do dia */}
      <section aria-label="Agenda de hoje">
        <div className="mb-3 flex items-center justify-between">
          <h2 className="flex items-center gap-2 font-serif text-lg font-semibold text-foreground">
            <Calendar className="size-4.5 text-primary" strokeWidth={1.5} />
            Sua agenda
          </h2>
          <span className="font-mono text-[11px] uppercase tracking-[0.18em] text-muted-foreground">
            {pendentes.length} pendentes
          </span>
        </div>
        <ul className="flex flex-col gap-2">
          {atividadesHoje
            .slice()
            .sort((a, b) => a.hora.localeCompare(b.hora))
            .map((atv) => (
              <li key={atv.id}>
                <div
                  className={`flex items-center gap-3 rounded-2xl border p-3.5 transition-brand ${
                    atv.concluida
                      ? 'border-border bg-muted/50 opacity-60'
                      : 'border-transparent bg-card shadow-soft'
                  }`}
                >
                  {atv.concluida ? (
                    <CheckCircle2 className="size-5 shrink-0 text-teal-mid" strokeWidth={1.5} />
                  ) : (
                    <Circle className="size-5 shrink-0 text-muted-foreground" strokeWidth={1.5} />
                  )}
                  <div className="min-w-0 flex-1">
                    <p
                      className={`truncate text-sm font-medium ${
                        atv.concluida ? 'text-muted-foreground line-through' : 'text-foreground'
                      }`}
                    >
                      {atv.titulo}
                    </p>
                    <p className="text-xs text-muted-foreground">{atv.cliente}</p>
                  </div>
                  <span className="font-mono text-xs font-medium text-primary">{atv.hora}</span>
                </div>
              </li>
            ))}
        </ul>
      </section>

      {/* Leads quentes */}
      <section aria-label="Leads quentes">
        <div className="mb-3 flex items-center justify-between">
          <h2 className="flex items-center gap-2 font-serif text-lg font-semibold text-foreground">
            <Flame className="size-4.5 text-amber" strokeWidth={1.5} />
            Leads quentes
          </h2>
          <button
            type="button"
            onClick={onVerFunil}
            className="flex items-center gap-0.5 text-xs font-semibold text-primary"
          >
            Ver funil
            <ChevronRight className="size-3.5" strokeWidth={2} />
          </button>
        </div>
        <ul className="flex flex-col gap-2">
          {leadsQuentes.map((lead) => (
            <li key={lead.id}>
              <button
                type="button"
                onClick={() => onVerCliente(lead.id)}
                className="flex w-full items-center gap-3 rounded-[1.25rem] border-transparent bg-card p-3.5 text-left shadow-soft transition-brand active:scale-[0.98]"
              >
                <span className="flex size-10 shrink-0 items-center justify-center rounded-full bg-primary/10 font-serif text-sm font-semibold text-primary">
                  {lead.iniciais}
                </span>
                <span className="min-w-0 flex-1">
                  <span className="block truncate text-sm font-semibold text-foreground">
                    {lead.nome}
                  </span>
                  <span className="block truncate text-xs text-muted-foreground">
                    {lead.interesse} · {lead.estagio}
                  </span>
                </span>
                <span
                  className={`shrink-0 rounded-full px-2.5 py-1 text-[10px] font-semibold uppercase tracking-wide ${tempConfig[lead.temperatura].chip}`}
                >
                  {tempConfig[lead.temperatura].label}
                </span>
              </button>
            </li>
          ))}
        </ul>
      </section>

      {/* Atalhos de contato */}
      <section aria-label="Resumo da carteira" className="rounded-2xl bg-cream p-4">
        <div className="flex items-center gap-3">
          <span className="flex size-10 items-center justify-center rounded-xl bg-primary text-primary-foreground">
            <Users2 className="size-5" strokeWidth={1.5} />
          </span>
          <div className="flex-1">
            <p className="text-sm font-semibold text-foreground">6 clientes ativos na carteira</p>
            <p className="text-xs text-muted-foreground">2 aguardam retorno hoje</p>
          </div>
          <Phone className="size-5 text-primary" strokeWidth={1.5} />
        </div>
      </section>
    </div>
  )
}
