'use client'

import { useState } from 'react'
import { MessageCircle, Phone, SlidersHorizontal } from 'lucide-react'
import { funil, tempConfig } from '@/lib/app-data'

export function ScreenNegocios({
  onVerCliente,
}: {
  onVerCliente: (id: string) => void
}) {
  const [modo, setModo] = useState<'venda' | 'locacao'>('venda')
  const [estagioAtivo, setEstagioAtivo] = useState(0)

  const total = funil.reduce((acc, e) => acc + e.leads.length, 0)

  return (
    <div className="flex h-full flex-col pb-24">
      <header className="px-5 pt-4">
        <div className="flex items-center justify-between">
          <h1 className="font-serif text-2xl font-semibold text-foreground">Negócios</h1>
          <button
            type="button"
            aria-label="Filtros"
            className="flex size-10 items-center justify-center rounded-full border border-border bg-card text-foreground transition-brand active:scale-95"
          >
            <SlidersHorizontal className="size-5" strokeWidth={1.5} />
          </button>
        </div>
        <p className="mt-0.5 font-mono text-[11px] uppercase tracking-[0.18em] text-muted-foreground">
          {total} negociações abertas
        </p>

        {/* Segmented control Venda / Locação */}
        <div className="mt-4 flex rounded-xl bg-muted p-1" role="tablist" aria-label="Tipo de negócio">
          {(['venda', 'locacao'] as const).map((m) => (
            <button
              key={m}
              type="button"
              role="tab"
              aria-selected={modo === m}
              onClick={() => setModo(m)}
              className={`flex-1 rounded-lg py-2 text-sm font-semibold transition-brand ${
                modo === m ? 'bg-card text-primary shadow-sm' : 'text-muted-foreground'
              }`}
            >
              {m === 'venda' ? 'Venda' : 'Locação'}
            </button>
          ))}
        </div>

        {/* Chips de estágio */}
        <div className="mt-4 flex gap-2 overflow-x-auto scrollbar-none -mx-5 px-5">
          {funil.map((estagio, i) => (
            <button
              key={estagio.id}
              type="button"
              onClick={() => setEstagioAtivo(i)}
              className={`flex shrink-0 items-center gap-2 rounded-full px-4 py-2 text-sm font-semibold transition-brand ${
                estagioAtivo === i
                  ? 'bg-primary text-primary-foreground'
                  : 'border border-border bg-card text-muted-foreground'
              }`}
            >
              {estagio.nome}
              <span
                className={`flex size-5 items-center justify-center rounded-full font-mono text-[11px] ${
                  estagioAtivo === i ? 'bg-teal-shadow/40 text-primary-foreground' : 'bg-muted text-slate'
                }`}
              >
                {estagio.leads.length}
              </span>
            </button>
          ))}
        </div>
      </header>

      {/* Colunas do funil com swipe horizontal */}
      <div className="mt-4 flex-1 overflow-hidden">
        <div
          className="flex h-full transition-transform duration-200 ease-[cubic-bezier(0.2,0.8,0.2,1)]"
          style={{ transform: `translateX(-${estagioAtivo * 100}%)` }}
        >
          {funil.map((estagio) => (
            <div key={estagio.id} className="w-full shrink-0 overflow-y-auto px-5">
              {estagio.leads.length === 0 ? (
                <p className="mt-10 text-center text-sm text-muted-foreground">
                  Nenhum negócio neste estágio.
                </p>
              ) : (
                <ul className="flex flex-col gap-3">
                  {estagio.leads.map((lead) => (
                    <li key={lead.id}>
                      <article className="rounded-[1.25rem] border-transparent bg-card shadow-soft p-4">
                        <button
                          type="button"
                          onClick={() => onVerCliente(lead.id)}
                          className="flex w-full items-start gap-3 text-left"
                        >
                          <span className="flex size-10 shrink-0 items-center justify-center rounded-full bg-primary/10 font-serif text-sm font-semibold text-primary">
                            {lead.iniciais}
                          </span>
                          <span className="min-w-0 flex-1">
                            <span className="flex items-center gap-2">
                              <span className="truncate text-sm font-semibold text-foreground">
                                {lead.nome}
                              </span>
                              <span
                                className={`size-2 shrink-0 rounded-full ${tempConfig[lead.temperatura].dot}`}
                                aria-label={`Temperatura: ${tempConfig[lead.temperatura].label}`}
                              />
                            </span>
                            <span className="block truncate text-xs text-muted-foreground">
                              {lead.interesse}
                            </span>
                            <span className="mt-1 block font-mono text-sm font-medium text-primary">
                              {lead.valor}
                            </span>
                          </span>
                        </button>
                        <div className="mt-3 flex items-center justify-between border-t border-border pt-3">
                          <span className="font-mono text-[10px] uppercase tracking-[0.14em] text-muted-foreground">
                            {lead.origem} · {lead.atualizado}
                          </span>
                          <div className="flex gap-2">
                            <button
                              type="button"
                              onClick={() => onVerCliente(lead.id)}
                              className="rounded-full bg-primary/10 px-3 py-1.5 text-xs font-semibold text-primary transition-brand active:scale-95"
                            >
                              Abrir
                            </button>
                            <button
                              type="button"
                              aria-label={`WhatsApp de ${lead.nome}`}
                              className="flex size-8 items-center justify-center rounded-full bg-primary text-primary-foreground transition-brand active:scale-95"
                            >
                              <MessageCircle className="size-4" strokeWidth={1.5} />
                            </button>
                          </div>
                        </div>
                      </article>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
